                                            Text(
                                                "Player: ${GameState.getCurrentPlayer()}",
                                                style = MaterialTheme.typography.labelSmall
                                            )
                                        }
                                    }
                                },
                                actions = {
                                    IconButton(onClick = { showDevMenu = true }) {
                                        Icon(
                                            Icons.Default.Build, 
